// @/src/hooks/useNotification.ts
import { createContext, useContext, useState } from 'react';
import { HTMLHuelNotificationElement } from 'huel-notification';

interface NotificationProps {
  heading: string;
  subheading: string;
  type: string;
}

interface UseNotificationReturn {
  notify: (props: NotificationProps) => Promise<void>;
  notificationElem: HTMLHuelNotificationElement | null;
}

const NotificationContext = createContext<HTMLHuelNotificationElement | null>(null);

const useNotification = (): UseNotificationReturn => {
  const notificationElem = useContext(NotificationContext);
  const [error, setError] = useState(null);

  const notify = async (props: NotificationProps) => {
    if (!notificationElem) return;

    try {
      await notificationElem.open({
        heading: props.heading,
        subheading: props.subheading,
        type: props.type,
      });
    } catch (error) {
      setError(error);
    }
  };

  return { notify, notificationElem, error };
};

export default useNotification;
